from enum import Enum
from plum import dispatch
from typing import TypeVar, Union, Generic, List, Tuple
from spire.pdf.common import *
from spire.pdf import *
from ctypes import *
import abc

class OfdConverter(SpireObject):
    """
    This class provides support for converting ofd into pdf or image.
    """
    @dispatch
    def __init__(self, filename:str):
        GetDllLibPdf().spr_pdf_OfdConverter_CreateOfdConverterF.argtypes=[c_wchar_p]
        GetDllLibPdf().spr_pdf_OfdConverter_CreateOfdConverterF.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_OfdConverter_CreateOfdConverterF,filename)
        super(OfdConverter, self).__init__(intPtr)

    @dispatch
    def __init__(self, stream:Stream):
        intPtrstream:c_void_p = stream.Ptr
        GetDllLibPdf().spr_pdf_OfdConverter_CreateOfdConverterS.argtypes=[c_void_p]
        GetDllLibPdf().spr_pdf_OfdConverter_CreateOfdConverterS.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_OfdConverter_CreateOfdConverterS,intPtrstream)
        super(OfdConverter, self).__init__(intPtr)

    @property
    def PageCount(self) -> int:
        """
        Gets the document page count.
        """
        GetDllLibPdf().spr_pdf_OfdConverter_get_PageCount.argtypes = [c_void_p]
        GetDllLibPdf().spr_pdf_OfdConverter_get_PageCount.restype = c_int
        ret = CallCFunction(GetDllLibPdf().spr_pdf_OfdConverter_get_PageCount,self.Ptr)
        return ret

    @dispatch
    def ToPdf(self, filename: str):
        """
        Save ofd document to pdf.
        Args: filename: A relative or absolute path for the file.
        """
        GetDllLibPdf().spr_pdf_OfdConverter_ToPdf.argtypes = [c_void_p, c_wchar_p]
        CallCFunction(GetDllLibPdf().spr_pdf_OfdConverter_ToPdf,self.Ptr, filename)

    @dispatch
    def ToPdf(self, stream: Stream):
        """
        Save ofd document to pdf.
        Args: stream: The pdf file stream.
        """
        intPtrstream: c_void_p = stream.Ptr
        GetDllLibPdf().spr_pdf_OfdConverter_ToPdfS.argtypes = [c_void_p, c_void_p]
        CallCFunction(GetDllLibPdf().spr_pdf_OfdConverter_ToPdfS,self.Ptr, intPtrstream)

    @dispatch
    def ToImage(self, pageIndex: int) -> Stream:
        """
        Saves OFD document page as image.
        Args: pageIndex: Page index.
        Returns: Returns page as Image.
        """
        GetDllLibPdf().spr_pdf_OfdConverter_ToImage.argtypes = [c_void_p, c_int]
        GetDllLibPdf().spr_pdf_OfdConverter_ToImage.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_OfdConverter_ToImage,self.Ptr, pageIndex)
        ret = None if intPtr == None else Stream(intPtr)
        return ret

    @dispatch
    def ToImage(self, pageIndex: int, dpiX: int, dpiY: int) -> Stream:
        """
        Saves OFD document page as image.
        Args: pageIndex: Page index.
        Args: dpiX: Pictures X resolution.
        Args: dpiY: Pictures Y resolution.
        Returns: Returns page as Image.
        """
        GetDllLibPdf().spr_pdf_OfdConverter_ToImagePDD.argtypes = [c_void_p, c_int, c_int, c_int]
        GetDllLibPdf().spr_pdf_OfdConverter_ToImagePDD.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_OfdConverter_ToImagePDD,self.Ptr, pageIndex, dpiX, dpiY)
        ret = None if intPtr == None else Stream(intPtr)
        return ret

    def Dispose(self):
        """
        """
        GetDllLibPdf().spr_pdf_OfdConverter_Dispose.argtypes = [c_void_p]
        CallCFunction(GetDllLibPdf().spr_pdf_OfdConverter_Dispose,self.Ptr)